// GA4 runReport response -> fact_web_daily rows at date x region x hostname grain.
const resp = $input.first().json;
const rows = resp.rows || [];

// countryId is ISO 3166-1 alpha-2
function regionFromAlpha2(cc) {
  const c = String(cc || '').toUpperCase();
  if (['GB', 'IE', 'IM', 'GG', 'JE'].includes(c)) return 'UKI';
  if (['BE', 'LU'].includes(c)) return 'BeLux';
  if (c === 'NL') return 'NL';
  return 'UNASSIGNED';
}

const agg = {};
let issues = 0;
for (const r of rows) {
  const d = (r.dimensionValues || []).map((v) => v.value);
  const m = (r.metricValues || []).map((v) => Number(v.value) || 0);
  const raw = String(d[0] || '');
  if (raw.length !== 8 || isNaN(Number(raw))) { issues++; continue; }
  const date = raw.slice(0, 4) + '-' + raw.slice(4, 6) + '-' + raw.slice(6, 8);
  const region = regionFromAlpha2(d[1]);
  const host = String(d[2] || '');
  const key = date + '|' + region + '|' + host;
  if (!agg[key]) {
    agg[key] = { activity_date: date, region_code: region, hostname: host,
      sessions: 0, key_events: 0, engaged_sessions: 0, source: 'ga4' };
  }
  agg[key].sessions += m[0] || 0;
  agg[key].key_events += m[1] || 0;
  agg[key].engaged_sessions += m[2] || 0;
}

const out = Object.values(agg);
if (out.length === 0) {
  throw new Error('GA4 returned 0 usable rows - check property ID, access grant (aarav@braind.io as Viewer) and date range');
}
const rowsIn = rows.length;
const meta = { rows_in: rowsIn, issues: issues, issue_pct: rowsIn ? Number(((issues / rowsIn) * 100).toFixed(2)) : 0 };
return out.map((json) => ({ json: Object.assign({}, json, { _meta: meta }) }));
